import sys

class Solution:
    def longestSubarray(self, nums: list[int], k: int) -> int:
        if not nums:
            return 0
        left = 0
        current_sum = 0
        max_length = 0
        for right in range(len(nums)):
            current_sum += nums[right]
            while current_sum > k and left <= right:
                current_sum -= nums[left]
                left += 1
            if current_sum == k:
                max_length = max(max_length, right - left + 1)
        return max_length

