#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int longestSubarray(vector<int>& nums, int k) {
        int left = 0;
        int current_sum = 0;
        int max_length = 0;
        for (int right = 0; right < nums.size(); right++) {
            current_sum += nums[right];
            while (current_sum > k && left <= right) {
                current_sum -= nums[left];
                left++;
            }
            if (current_sum == k) {
                max_length = max(max_length, right - left + 1);
            }
        }
        return max_length;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.longestSubarray(nums, k);
    cout << ans << "\n";
    return 0;
}
